'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { signOut } from 'firebase/auth';
import { auth } from '@/lib/firebase';
import BottomNav from '@/components/BottomNav';

export default function ProfilePage() {
  const { user, profile, loading } = useAuth();
  const router = useRouter();
  const [scoreAnimated, setScoreAnimated] = useState(false);
  const [nimBio, setNimBio] = useState<string | null>(null);
  const [generatingBio, setGeneratingBio] = useState(false);

  useEffect(() => {
    if (!loading && !user) router.push('/auth');
  }, [user, loading, router]);

  useEffect(() => {
    setTimeout(() => setScoreAnimated(true), 200);
  }, []);

  const handleLogout = async () => {
    await signOut(auth);
    router.push('/auth');
  };

  const getInitials = (name: string) =>
    name.split(/\s+/).map((w: string) => w[0]).join('').slice(0, 2).toUpperCase();

  const generateBioWithNIM = async () => {
    if (!profile) return;
    setGeneratingBio(true);
    try {
      const res = await fetch('/api/nim', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'generate-aboutme',
          payload: {
            techSkills: profile.techSkills,
            nonTechSkills: profile.nonTechSkills,
            college: profile.college,
            hackathons: profile.hackathons,
            papers: profile.papers,
            internships: profile.internships,
          },
        }),
      });
      if (res.ok) {
        const { aboutMe } = await res.json();
        setNimBio(aboutMe);
      }
    } catch { /* graceful */ }
    finally { setGeneratingBio(false); }
  };

  if (loading || !profile) return <div className="loading-page"><div className="spinner" /></div>;

  const portfolioLinks = [
    { icon: '🐱', name: 'GitHub', val: profile.github },
    { icon: '🔗', name: 'LinkedIn', val: profile.linkedin },
    { icon: '📊', name: 'LeetCode', val: profile.leetcode },
    { icon: '👨‍🍳', name: 'CodeChef', val: profile.codechef },
    { icon: '⚔️', name: 'HackerRank', val: profile.hackerrank },
  ].filter((l) => l.val);

  return (
    <div className="app-shell">
      <header className="c-header">
        <span className="c-logo">Campus<span>Link</span></span>
        <button className="auth-link" onClick={handleLogout} style={{ fontSize: 12 }}>Sign out</button>
      </header>

      <div className="page-content">
        <div className="profile-wrap">
          <div className="profile-hero">
            <div className="profile-avatar">{getInitials(profile.codeName)}</div>
            <div className="profile-codename">{profile.codeName}</div>
            <div className="profile-type">
              {profile.college} · {profile.isStudent ? 'Student' : 'Professional'}
            </div>

            <div className="profile-score-row">
              <div className="ps-item">
                <span className="ps-num">{profile.collaborationCount}</span>
                <span className="ps-lbl">Collabs</span>
              </div>
              <div className="ps-divider" />
              <div className="ps-item">
                <span className="ps-num">{profile.hackathons.length}</span>
                <span className="ps-lbl">Hackathons</span>
              </div>
              <div className="ps-divider" />
              <div className="ps-item">
                <span className="ps-num">{profile.score}</span>
                <span className="ps-lbl">Score</span>
              </div>
            </div>

            <div className="rating-bar-wrap">
              <div className="rating-bar-label">
                <span>Collaboration Score</span>
                <span>{profile.score}/100</span>
              </div>
              <div className="rating-bar">
                <div
                  className="rating-bar-fill"
                  style={{ width: scoreAnimated ? `${profile.score}%` : '0%' }}
                />
              </div>
            </div>
          </div>

          {/* About Me */}
          <div className="profile-section">
            <div className="profile-section-title">About</div>
            <p style={{ fontSize: 13, color: 'var(--subtle)', lineHeight: 1.7, fontWeight: 300, fontStyle: 'italic' }}>
              &ldquo;{nimBio || profile.aboutMe}&rdquo;
            </p>
            {nimBio && (
              <div style={{ marginTop: 8 }}>
                <span className="nim-badge">✦ AI Generated</span>
              </div>
            )}
            <button
              onClick={generateBioWithNIM}
              disabled={generatingBio}
              style={{ marginTop: 10, fontSize: 11, color: 'var(--subtle)', background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4 }}
            >
              {generatingBio ? '✦ Generating...' : '✦ Generate with AI'}
            </button>
          </div>

          {/* Tech Skills */}
          <div className="profile-section">
            <div className="profile-section-title">Tech Skills</div>
            <div className="tags-wrap">
              {profile.techSkills.map((s: string) => (
                <span key={s} className="profile-tag">{s}</span>
              ))}
            </div>
          </div>

          {/* Non-Tech Skills */}
          {profile.nonTechSkills.length > 0 && (
            <div className="profile-section">
              <div className="profile-section-title">Non-Tech Skills</div>
              <div className="tags-wrap">
                {profile.nonTechSkills.map((s: string) => (
                  <span key={s} className="profile-tag hollow">{s}</span>
                ))}
              </div>
            </div>
          )}

          {/* Activity */}
          <div className="profile-section">
            <div className="profile-section-title">Activity</div>
            <div className="tags-wrap">
              {profile.hackathons.length > 0 && <span className="profile-tag">{profile.hackathons.length} Hackathons</span>}
              {profile.papers > 0 && <span className="profile-tag">{profile.papers} Papers</span>}
              {profile.patents > 0 && <span className="profile-tag">{profile.patents} Patents</span>}
              {profile.certifications.length > 0 && <span className="profile-tag">{profile.certifications.length} Certs</span>}
              {profile.internships.length > 0 && <span className="profile-tag">{profile.internships.length} Internships</span>}
              {profile.cgpa > 0 && <span className="profile-tag">CGPA {profile.cgpa}</span>}
            </div>
          </div>

          {/* Portfolio Links */}
          {portfolioLinks.length > 0 && (
            <div className="profile-section">
              <div className="profile-section-title">Portfolio</div>
              <div className="portfolio-links">
                {portfolioLinks.map((l) => (
                  <a key={l.name} href={l.val} target="_blank" rel="noopener noreferrer" className="portfolio-link">
                    <span className="pl-icon">{l.icon}</span>
                    <span className="pl-name">{l.name}</span>
                    <span className="pl-val">↗</span>
                  </a>
                ))}
              </div>
            </div>
          )}

          {/* Member Since */}
          <div className="profile-section">
            <div className="profile-section-title">Member Since</div>
            <p style={{ fontSize: 13, color: 'var(--subtle)' }}>
              {new Date(profile.dateJoined).toLocaleDateString('en-US', { month: 'long', year: 'numeric' })} ·&nbsp;
              <span style={{ color: 'var(--light)' }}>Anonymous by default</span>
            </p>
          </div>

          <button className="edit-profile-btn" onClick={() => router.push('/profile/edit')}>
            Edit Profile
          </button>

          <button className="edit-profile-btn" style={{ marginTop: 8, borderColor: 'var(--border)', color: 'var(--muted)' }} onClick={() => router.push('/projects/my')}>
            My Projects
          </button>
        </div>
      </div>

      <BottomNav />
    </div>
  );
}
